var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"좋아. 코스튬 재료도 잔뜩 모았고. 청소도 대충 이쯤이면 되겠지.","JPN":"よし。コスチュームの材料もたくさん集めたし。掃除もこのくらいでいいよね。","ENG":"Okay. We got all the materials for the costumes, and it looks pretty clean here now.","TWN":"好，服裝材料也收集了很多，打掃到這程度應該就可以了吧。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"실전은 오랜만이네요. 갑자기 이런 복장으로 싸우게 될 줄은 몰랐지만.","JPN":"実戦は久しぶりですね。いきなりこんな服装で戦うことになるとは思っていませんでしたけど。","ENG":"It's been a long time since I've fought. I didn't know it would be so difficult to fight in an outfit like this, however.","TWN":"好久沒有實戰了，沒想到會突然穿著這種服裝戰鬥。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"심의회라고 했나? 수녀님도 꽤 제법이네.","JPN":"審議会だっけ？　シスターもなかなかやるね。","ENG":"Did you say you were from the Investigation Council? You fight pretty good for a Sister.","TWN":"議會是吧？修女也挺厲害的嘛。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"그보다 신기하네요. 카페의 지하실이 이면세계와 연결되어 있다니.","JPN":"それより不思議ですね。カフェの地下室が裏世界と繋がっているなんて。","ENG":"It's interesting to see the basement of a cafe be connected to the Counterside.","TWN":"比這個更神奇的是，咖啡廳的地下室竟然與異界相連。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"특정한 좌표의 이면세계를 어딘가에 연결하는 기술이 있다는 건 처음 알았네요.","JPN":"特定座標の裏世界をどこかに繋げる技術があるということを初めて知りました。","ENG":"I didn't know until now that there is a technology that certain coordinates are connected to somewhere in the Counterside.","TWN":"原來還有特定座標可以連接異界某處的技術啊。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"여기 오는 사람들은 다 그 소리 하더라?","JPN":"ここに来る人はみんなそう言うんだよね。","ENG":"Everyone who comes here seems to say that.","TWN":"來這裡的人都這麼說。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"원리 같은 건 잘 모르는데, 마법으로 좌표를 고정해 둔 거래.","JPN":"原理はよくわかんないけど、魔法で座標を固定したんだって。","ENG":"We don't know how it works, but we're told magic was used to fix the coordinates.","TWN":"原理什麼的我不太清楚，不過好像是用魔法固定了座標。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"카페 주변에서 침식 현상이 발생하지 않는 것도 주기적으로 여길 청소해서 그런 거고.","JPN":"カフェの周りで侵食現象が発生しないのも、定期的にここを掃除するからだし。","ENG":"And the reason why there are no Counterside Effects around the cafe is because we regularly sweep the basement.","TWN":"咖啡廳周圍沒有發生侵蝕現象，也是因為定期在這裡打掃的緣故。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"그렇군요. 그래서 청소라고…….","JPN":"そうなのですか。だから、掃除って……","ENG":"I see. So that's what \\"cleaning\\" meant...","TWN":"這樣啊，所以是特別的打掃……"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"아, 맞다. 이 지하실에 관한 건 비밀이다?","JPN":"あっ、そうだ。この地下室のことは内緒ね。","ENG":"Oh, right. The thing about the basement is a secret, okay?","TWN":"啊，對了，關於這個地下室的事情是秘密喔？"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"외부인을 끌어들였다는 걸 라우라가 알면, 귀찮아지거든.","JPN":"部外者を巻き込んだことをラウラが知ると、面倒くさくなるから。","ENG":"If Laura finds out that we brought an outsider down there, things will become troublesome.","TWN":"如果蘿拉知道我們帶外人來，會很麻煩的。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"후후, 걱정 마세요. 주님을 따르는 이들은 침묵을 미덕으로 여긴답니다.","JPN":"ふふ、心配しないでください。神に従う者たちは沈黙こそ美徳であると思っていますよ。","ENG":"Haha, don't worry. Those who follow the Lord consider silence a virtue.","TWN":"呵呵，不用擔心。追隨主的人們視沉默為美德。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"INGRID_STREGA_NULL_CAFFE","text":{"KOREA":"그런가…? 그 전기톱 꼬맹이는 꽤 요란스러웠던 것 같은데…….","JPN":"そうかな……？　あのチェーンソーのチビちゃんは結構騒がしかったような……","ENG":"Do they...? That chainsaw kid was pretty talkative, if you catch my drift...","TWN":"是嗎…？那個拿電鋸的小鬼好像挺吵的……"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"앗, 폐점 시간에 딱 맞춰서 돌아왔네.","JPN":"あっ、閉店時間ぴったりに戻ってきたね。","ENG":"Oh, look. You're back just in time for closing.","TWN":"啊，剛好趕在關門時間回來了。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"고생했어, 잉그리드. 수녀님도 진짜 고생 많으셨어요.","JPN":"お疲れ様、イングリッド。シスターも本当にお疲れ様でした。","ENG":"You did good, Ingrid. And thank you for helping, Sister.","TWN":"辛苦了，英格麗。修女你也真的辛苦了。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"천만에요, 유나 씨. 신세는 저희 자매님이 먼저 지신 걸요.","JPN":"とんでもないです、ユナさん。そもそもシスター・シンディがお世話になってますから。","ENG":"You're welcome, Yuna. But I am just returning the favor.","TWN":"哪裡的話，尤娜。是我們姊妹先領受了你的恩惠。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"그보다 옷을 만든다고 하지 않았나요? 이런 재료들로 정말 옷을 만들 수 있는 건가요?","JPN":"それより、服を作ると言っていませんでしたか？　本当にこんな材料で服を作れるのですか？","ENG":"By the way, didn't you say you were making clothes? Can you really make clothes with these materials?","TWN":"比起這個，你不是說要做衣服嗎？用這些材料真的能做出衣服嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"아하하… 재료가 조금 괴팍해 보이긴 하죠.","JPN":"あはは……材料がちょっと変わってますよね。","ENG":"Ah hah hah... I know the materials look a bit odd.","TWN":"啊哈哈……材料看起來有點奇怪吧。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"이대로 바로 쓰는 건 아니고, 몇 번 가공을 거치면 의상 재료로 사용할 수 있더라고요.","JPN":"このまま使うわけじゃなくて、何回か加工すると衣装の材料として使えるらしいんです。","ENG":"We can't use them like this, and they will only be used as garments after going through a few processes.","TWN":"不能直接使用，需要經過幾次加工後才能作為服裝材料使用。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"그렇군요. 스트레가 분들은 참 신기한 기술을 많이 알고 계시네요.","JPN":"そうなんですか。ストレガのみなさんは本当に不思議な技術をたくさん知っていますね。","ENG":"I see. Strega seems to know about a lot of amazing skills.","TWN":"原來如此，史特雷加的人真是懂得很多神奇的技術呢。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"INGRID_STREGA_NULL_CAFFE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"저… 그래서 말인데…….","JPN":"あの……それでなんですけど……","ENG":"Um... By the way...","TWN":"我……那個……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"혹시 두 분께 실례가 안 된다면, 한 가지 부탁드리고 싶은 게 있는데요.","JPN":"もしお二人に失礼でなければ、1つお願いしたいことがあるのです。","ENG":"There is a favor I would like to ask if you two don't mind.","TWN":"如果不介意的話，我有個請求想拜託兩位。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOO_NA_STREGA_NULL_CAFFE","text":{"KOREA":"네? 부탁이요?","JPN":"え？　お願いですか？","ENG":"Huh? A favor?","TWN":"啊？請求嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"YOO_NA_STREGA_NULL_CAFFE","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};